revision.text:
/* {{pp-template}} */
.fake-heading {
	color: var(--color-emphasized, #000000);
	background: none;
	margin: 0;
	overflow: hidden;
	padding-bottom: 0.17em;
	page-break-after: avoid;
	padding-top: 0.5em;
}

.fake-heading.h1,
.fake-heading.h2 {
	border-bottom: 1px solid var(--border-color-base, #a2a9b1);
	margin-bottom: 0.25em;
	margin-top: 1em;
	padding: 0;
	font-family: 'Linux Libertine','Georgia','Times','Source Serif Pro',serif;
	line-height: 1.375;
}

body.skin-monobook .fake-heading.h1,
body.skin-monobook .fake-heading.h2 {
	font-family: inherit;
	line-height: inherit;
}

body.skin-timeless .fake-heading.h1,
body.skin-timeless .fake-heading.h2 {
	border-bottom: 3px solid #c8ccd1;
}

.fake-heading.h1 {
	font-size: 1.8em;
}

body.skin-timeless .fake-heading.h1 {
	font-size: 2em;
}

.fake-heading.h2 {
	font-size: 1.5em;
}

body.skin-timeless .fake-heading.h2 {
	font-size: 1.8em;
}

.fake-heading.h3,
.fake-heading.h4,
.fake-heading.h5,
.fake-heading.h6 {
	font-weight: bold;
	margin-top: 0.3em;
	margin-bottom: 0;
	padding-bottom: 0;
	line-height: 1.6;
}

.fake-heading.h3 {
	font-size: 1.2em;
}

.fake-heading.h4 {
	font-size: 100%;
}

