	border-bottom: 3px solid #c8ccd1;
}

.fake-heading.h1 {
	font-size: 1.8em;
}

body.skin-timeless .fake-heading.h1 {
	font-size: 2em;
}

.fake-heading.h2 {
	font-size: 1.5em;
}

body.skin-timeless .fake-heading.h2 {
	font-size: 1.8em;
}

.fake-heading.h3,
.fake-heading.h4,
.fake-heading.h5,
.fake-heading.h6 {
	font-weight: bold;
	margin-top: 0.3em;
	margin-bottom: 0;
	padding-bottom: 0;
	line-height: 1.6;
}

.fake-heading.h3 {
	font-size: 1.2em;
}

.fake-heading.h4 {
	font-size: 100%;
}
